1	import { useState, useEffect, useCallback, useRef } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import {
4	  generateUserKeyPair,
5	  backupPrivateKeyV1,
6	  restorePrivateKey,
7	  restorePrivateKeyV1,
8	  isV2Key,
9	} from "@/lib/e2e-crypto";
10	import { idbGetPrivateKey, idbStorePrivateKey, idbStorePublicKeyJwk, idbClear } from "@/lib/indexeddb-crypto";
11	
12	export type E2EEStatus = "idle" | "initializing" | "ready" | "needs_recovery_password" | "error";
13	
14	export interface UseInitializeE2EEResult {
15	  status: E2EEStatus;
16	  error: Error | null;
17	  retry: () => void;
18	  // Raised when the user is on a NEW device and has a v2 (password-protected) backup.
19	  // Show a recovery password modal and call provideRecoveryPassword() with the input.
20	  needsRecoveryPassword: boolean;
21	  // Raised when the user's backup was silently auto-restored from the legacy v1 scheme
22	  // (userId-wrapped). Show a migration prompt so they can set a real recovery password.
23	  needsMigration: boolean;
24	  // Call this from the recovery password modal when the user submits their password.
25	  provideRecoveryPassword: (password: string) => Promise<void>;
26	  // Call this after the user completes migration (sets a recovery password via key-migration.ts).
27	  clearMigrationFlag: () => void;
28	}
29	
30	const TAG = "[E2EE Init]";
31	
32	export function useInitializeE2EE(userId: string): UseInitializeE2EEResult {
33	  const [status, setStatus] = useState<E2EEStatus>("idle");
34	  const [error, setError] = useState<Error | null>(null);
35	  const [attempt, setAttempt] = useState(0);
36	  const [needsRecoveryPassword, setNeedsRecoveryPassword] = useState(false);
37	  const [needsMigration, setNeedsMigration] = useState(false);
38	
39	  // Holds Supabase backup data while we wait for the user to type their password.
40	  const pendingRecoveryRef = useRef<{
41	    encryptedPrivateKey: string;
42	    keySalt: string;
43	    publicKey: string | null;
44	  } | null>(null);
45	
46	  useEffect(() => {
47	    if (!userId) return;
48	
49	    let cancelled = false;
50	
51	    const run = async () => {
52	      setStatus("initializing");
53	      setError(null);
54	
55	      try {
56	        // ── Step 1: Check IndexedDB ───────────────────────────────────────────
57	        const cachedPrivateKey = await idbGetPrivateKey(userId);
58	
59	        // ── Step 2: Check Supabase ────────────────────────────────────────────
60	        const { data, error: fetchError } = await supabase
61	          .from("user_encryption_keys")
62	          .select("public_key, encrypted_private_key, key_salt")
63	          .eq("user_id", userId)
64	          .maybeSingle();
65	
66	        if (cancelled) return;
67	
68	        if (fetchError) {
69	          const isNetworkError = !fetchError.code && !fetchError.status;
70	          if (isNetworkError) {
71	            throw new Error(`Network error fetching encryption keys: ${fetchError.message}`);
72	          }
73	          console.warn(`${TAG} Supabase fetch warning (non-fatal):`, fetchError.message);
74	        }
75	
76	        const hasSupabaseRecord = !!data && !fetchError;
77	
78	        // ── Happy path: IDB + Supabase both have data ─────────────────────────
79	        if (hasSupabaseRecord && cachedPrivateKey) {
80	          console.log(`${TAG} ✅ Already initialised`);
81	          if (!cancelled) setStatus("ready");
82	          return;
83	        }
84	
85	        // ── Cross-device recovery: Supabase has backup, IDB is empty ─────────
86	        if (hasSupabaseRecord && !cachedPrivateKey) {
87	          const { public_key, encrypted_private_key, key_salt } = data!;
88	
89	          if (encrypted_private_key && key_salt) {
90	            if (isV2Key(encrypted_private_key)) {
91	              // v2 key: cannot restore without the user's recovery password.
92	              // Park the data in a ref, update status, and wait for UI input.
93	              console.log(`${TAG} 🔐 v2 backup detected — recovery password required`);
94	              pendingRecoveryRef.current = {
95	                encryptedPrivateKey: encrypted_private_key,
96	                keySalt: key_salt,
97	                publicKey: public_key ?? null,
98	              };
99	              if (!cancelled) {
100	                setNeedsRecoveryPassword(true);
101	                setStatus("needs_recovery_password");
102	              }
103	              return;
104	            } else {
105	              // v1 key: auto-restore using userId as the PBKDF2 input (backward compat).
106	              // Flag for migration immediately after — the user needs to set a real password.
107	              console.log(`${TAG} 🔄 v1 backup detected — auto-restoring, migration required`);
108	              await restorePrivateKeyV1(userId, encrypted_private_key, key_salt);
109	              if (public_key) {
110	                try { await idbStorePublicKeyJwk(userId, JSON.parse(public_key)); } catch { /* non-fatal */ }
111	              }
112	              console.log(`${TAG} ✅ v1 key restored — flagging for migration`);
113	              if (!cancelled) {
114	                setStatus("ready");
115	                setNeedsMigration(true);
116	              }
117	              return;
118	            }
119	          }
120	
121	          // Remote record exists but backup columns are empty (legacy row with no backup).
122	          // Fall through to regenerate.
123	          console.log(`${TAG} ⚠️ Remote record has no private key backup — regenerating...`);
124	        }
125	
126	        // ── Key generation: no usable keys found anywhere ─────────────────────
127	        // This only runs for brand-new users (no Supabase record at all).
128	        // Existing users will always hit one of the paths above.
129	        console.log(`${TAG} 🔑 Generating new RSA-OAEP key pair...`);
130	        const { publicKeyJwk, privateKey } = await generateUserKeyPair();
131	
132	        await idbStorePrivateKey(userId, privateKey);
133	        await idbStorePublicKeyJwk(userId, publicKeyJwk);
134	
135	        // New users: use a v1 backup (userId-keyed, no v2: prefix) so the key is
136	        // auto-restorable on a new device before they set a recovery password.
137	        // The migration prompt (needsMigration: true) will upgrade them to v2.
138	        const { encryptedKey, saltBase64 } = await backupPrivateKeyV1(userId, privateKey);
139	
140	        const { error: upsertError } = await supabase
141	          .from("user_encryption_keys")
142	          .upsert(
143	            {
144	              user_id: userId,
145	              public_key: JSON.stringify(publicKeyJwk),
146	              encrypted_private_key: encryptedKey,
147	              key_salt: saltBase64,
148	              updated_at: new Date().toISOString(),
149	            },
150	            { onConflict: "user_id" }
151	          );
152	
153	        if (upsertError) {
154	          throw new Error(`Failed to save encryption keys: ${upsertError.message}`);
155	        }
156	
157	        console.log(`${TAG} ✅ New key pair generated and synced`);
158	        if (!cancelled) {
159	          setStatus("ready");
160	          setNeedsMigration(true); // prompt them to set a recovery password immediately
161	        }
162	      } catch (err) {
163	        if (cancelled) return;
164	        console.error(`${TAG} ❌ Initialisation failed:`, err);
165	
166	        const isCorruptedState =
167	          err instanceof DOMException &&
168	          (err.name === "InvalidStateError" || err.name === "UnknownError");
169	
170	        if (isCorruptedState) {
171	          console.error(`${TAG} 💥 Corrupted IDB state — clearing and redirecting`);
172	          try {
173	            localStorage.clear();
174	            sessionStorage.clear();
175	            await idbClear();
176	          } catch { /* best-effort */ }
177	          window.location.replace("/auth");
178	          return;
179	        }
180	
181	        const wrapped = err instanceof Error ? err : new Error(String(err));
182	        setError(wrapped);
183	        setStatus("error");
184	      }
185	    };
186	
187	    run();
188	    return () => { cancelled = true; };
189	  }, [userId, attempt]);
190	
191	  // Called from the recovery password modal on a new device with a v2 backup.
192	  const provideRecoveryPassword = useCallback(async (password: string) => {
193	    const pending = pendingRecoveryRef.current;
194	    if (!pending) {
195	      console.error(`${TAG} provideRecoveryPassword called with no pending recovery data`);
196	      return;
197	    }
198	
199	    setError(null);
200	    setStatus("initializing");
201	
202	    try {
203	      await restorePrivateKey(
204	        userId,
205	        password,
206	        pending.encryptedPrivateKey,
207	        pending.keySalt
208	      );
209	
210	      if (pending.publicKey) {
211	        try { await idbStorePublicKeyJwk(userId, JSON.parse(pending.publicKey)); } catch { /* non-fatal */ }
212	      }
213	
214	      pendingRecoveryRef.current = null;
215	      setNeedsRecoveryPassword(false);
216	      setStatus("ready");
217	      console.log(`${TAG} ✅ v2 key restored with recovery password`);
218	    } catch (err) {
219	      // A DOMException (OperationError) from crypto.subtle.decrypt means wrong password.
220	      const isWrongPassword =
221	        err instanceof DOMException ||
222	        (err instanceof Error && err.name === "OperationError");
223	
224	      setError(
225	        new Error(isWrongPassword
226	          ? "Incorrect recovery password. Please try again."
227	          : `Restore failed: ${err instanceof Error ? err.message : String(err)}`
228	        )
229	      );
230	      // Keep status at needs_recovery_password so the modal stays open.
231	      setStatus("needs_recovery_password");
232	    }
233	  }, [userId]);
234	
235	  const clearMigrationFlag = useCallback(() => setNeedsMigration(false), []);
236	
237	  const retry = useCallback(() => setAttempt((n) => n + 1), []);
238	
239	  return {
240	    status,
241	    error,
242	    retry,
243	    needsRecoveryPassword,
244	    needsMigration,
245	    provideRecoveryPassword,
246	    clearMigrationFlag,
247	  };
248	}
