1	import { useCallback, useRef, useState } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import {
4	  initUserKeys,
5	  getUserPrivateKey,
6	  generateRoomKey,
7	  wrapRoomKey,
8	  unwrapRoomKey,
9	  encryptMessage,
10	  decryptMessage,
11	  cacheRoomKey,
12	  getCachedRoomKey,
13	  clearRoomKeyCache,
14	  isEncryptedContent,
15	  restorePrivateKeyV1,
16	  isV2Key,
17	} from "@/lib/e2e-crypto";
18	
19	export function useE2EEncryption(currentUserId: string) {
20	  const [e2eReady, setE2eReady] = useState(false);
21	  const publicKeyRef = useRef<JsonWebKey | null>(null);
22	  const initPromiseRef = useRef<Promise<void> | null>(null);
23	
24	  // Initialises local (IDB) key state for the current user.
25	  // Supabase sync is owned by useInitializeE2EE in App.tsx — this hook must not
26	  // write to user_encryption_keys or it will race against the app-level init and
27	  // risk overwriting a correctly backed-up key pair with a freshly generated one.
28	  const initEncryption = useCallback(async () => {
29	    if (!currentUserId || initPromiseRef.current) return;
30	
31	    initPromiseRef.current = (async () => {
32	      try {
33	        const { publicKeyJwk } = await initUserKeys(currentUserId);
34	        publicKeyRef.current = publicKeyJwk;
35	        setE2eReady(true);
36	      } catch (err) {
37	        console.error("E2EE init failed:", err);
38	        // Privacy by Default: do NOT set e2eReady on failure.
39	        // The send path will throw before writing an unencrypted message.
40	      }
41	    })();
42	
43	    await initPromiseRef.current;
44	  }, [currentUserId]);
45	
46	  // Gets the user's private key from IndexedDB, falling back to the encrypted Supabase backup.
47	  // This is the cross-device fix: new devices decrypt the backup and cache locally.
48	  const getOrRestorePrivateKey = useCallback(async (): Promise<CryptoKey | null> => {
49	    const cached = await getUserPrivateKey(currentUserId);
50	    if (cached) return cached;
51	
52	    const { data } = await supabase
53	      .from("user_encryption_keys")
54	      .select("encrypted_private_key, key_salt")
55	      .eq("user_id", currentUserId)
56	      .maybeSingle();
57	
58	    if (!data?.encrypted_private_key || !data?.key_salt) return null;
59	
60	    // v2 keys require a recovery password that this hook doesn't have access to.
61	    // useInitializeE2EE in App.tsx owns that restore flow. If we land here with a
62	    // v2 key, the user hasn't completed recovery yet — return null so the send path
63	    // fails loudly rather than silently dropping their message.
64	    if (isV2Key(data.encrypted_private_key)) {
65	      console.warn("getOrRestorePrivateKey: v2 key requires recovery password — use useInitializeE2EE");
66	      return null;
67	    }
68	
69	    try {
70	      return await restorePrivateKeyV1(currentUserId, data.encrypted_private_key, data.key_salt);
71	    } catch (err) {
72	      console.error("Failed to restore private key from backup:", err);
73	      return null;
74	    }
75	  }, [currentUserId]);
76	
77	  const getPublicKey = useCallback(async (userId: string): Promise<JsonWebKey | null> => {
78	    const { data } = await supabase
79	      .from("user_encryption_keys")
80	      .select("public_key")
81	      .eq("user_id", userId)
82	      .maybeSingle();
83	
84	    if (data?.public_key) {
85	      return JSON.parse(data.public_key);
86	    }
87	    return null;
88	  }, []);
89	
90	  const setupRoomEncryption = useCallback(async (roomId: string, memberUserIds: string[]) => {
91	    if (!currentUserId) return;
92	
93	    const privateKey = await getOrRestorePrivateKey();
94	    if (!privateKey) return;
95	
96	    const roomKey = await generateRoomKey();
97	    await cacheRoomKey(roomId, roomKey);
98	
99	    for (const memberId of memberUserIds) {
100	      const memberPublicKey = await getPublicKey(memberId);
101	      if (!memberPublicKey) continue;
102	
103	      try {
104	        const encryptedKey = await wrapRoomKey(roomKey, privateKey, memberPublicKey);
105	        await supabase.from("room_encrypted_keys" as any).upsert(
106	          {
107	            room_id: roomId,
108	            user_id: memberId,
109	            encrypted_by: currentUserId,
110	            encrypted_key: encryptedKey,
111	          },
112	          { onConflict: "room_id,user_id" }
113	        );
114	      } catch (err) {
115	        console.error(`Failed to wrap key for ${memberId}:`, err);
116	      }
117	    }
118	  }, [currentUserId, getPublicKey, getOrRestorePrivateKey]);
119	
120	  const getRoomKey = useCallback(async (roomId: string): Promise<CryptoKey | null> => {
121	    const cached = await getCachedRoomKey(roomId);
122	    if (cached) return cached;
123	
124	    if (!currentUserId) return null;
125	    const privateKey = await getOrRestorePrivateKey();
126	    if (!privateKey) return null;
127	
128	    const { data: keyRecord } = await supabase
129	      .from("room_encrypted_keys" as any)
130	      .select("encrypted_key, encrypted_by")
131	      .eq("room_id", roomId)
132	      .eq("user_id", currentUserId)
133	      .maybeSingle() as any;
134	
135	    if (!keyRecord?.encrypted_key) return null;
136	
137	    const encryptorPublicKey = await getPublicKey(keyRecord.encrypted_by);
138	    if (!encryptorPublicKey) return null;
139	
140	    try {
141	      const roomKey = await unwrapRoomKey(
142	        keyRecord.encrypted_key,
143	        privateKey,
144	        encryptorPublicKey
145	      );
146	      await cacheRoomKey(roomId, roomKey);
147	      return roomKey;
148	    } catch (err) {
149	      console.warn("Failed to unwrap room key:", err);
150	      return null;
151	    }
152	  }, [currentUserId, getPublicKey, getOrRestorePrivateKey]);
153	
154	  const encrypt = useCallback(async (plaintext: string, roomId: string): Promise<string | null> => {
155	    const roomKey = await getRoomKey(roomId);
156	    if (!roomKey) return null;
157	    return encryptMessage(plaintext, roomKey);
158	  }, [getRoomKey]);
159	
160	  const decrypt = useCallback(async (ciphertext: string, roomId: string): Promise<string> => {
161	    if (!isEncryptedContent(ciphertext)) return ciphertext;
162	    const roomKey = await getRoomKey(roomId);
163	    if (!roomKey) return "🔒 Encrypted message";
164	    const result = await decryptMessage(ciphertext, roomKey);
165	    if (result === "[Unable to decrypt message]") {
166	      await clearRoomKeyCache(roomId);
167	      const freshKey = await getRoomKey(roomId);
168	      if (!freshKey) return "🔒 Encrypted message";
169	      const retry = await decryptMessage(ciphertext, freshKey);
170	      return retry === "[Unable to decrypt message]" ? "🔒 Encrypted message" : retry;
171	    }
172	    return result;
173	  }, [getRoomKey]);
174	
175	  const decryptMessages = useCallback(async (
176	    messages: Array<{ content: string | null; room_id: string; is_encrypted: boolean; [key: string]: any }>
177	  ) => {
178	    const roomKeys = new Map<string, CryptoKey | null>();
179	
180	    return Promise.all(
181	      messages.map(async (msg) => {
182	        if (!msg.content) return msg;
183	
184	        // Privacy by Default: never render unencrypted text message content.
185	        // Non-text types (file, voice, invoice) store metadata only — allow through.
186	        if (!msg.is_encrypted) {
187	          if (msg.message_type === "text" || !msg.message_type) {
188	            return { ...msg, content: "🔒 [Sent before encryption]" };
189	          }
190	          return msg;
191	        }
192	
193	        let roomKey = roomKeys.get(msg.room_id);
194	        if (roomKey === undefined) {
195	          roomKey = await getRoomKey(msg.room_id);
196	          roomKeys.set(msg.room_id, roomKey);
197	        }
198	
199	        if (!roomKey) {
200	          return {
201	            ...msg,
202	            content: isEncryptedContent(msg.content) ? "[Encryption key unavailable]" : msg.content,
203	          };
204	        }
205	
206	        if (isEncryptedContent(msg.content)) {
207	          let decrypted = await decryptMessage(msg.content, roomKey);
208	          if (decrypted === "[Unable to decrypt message]") {
209	            await clearRoomKeyCache(msg.room_id);
210	            const freshKey = await getRoomKey(msg.room_id);
211	            if (freshKey) {
212	              const retry = await decryptMessage(msg.content, freshKey);
213	              decrypted = retry === "[Unable to decrypt message]" ? "🔒 Encrypted message" : retry;
214	              roomKeys.set(msg.room_id, freshKey);
215	            } else {
216	              decrypted = "🔒 Encrypted message";
217	            }
218	          }
219	          return { ...msg, content: decrypted };
220	        }
221	        return msg;
222	      })
223	    );
224	  }, [getRoomKey]);
225	
226	  // Redistributes the EXISTING room key to all members without generating a new one.
227	  // Call this when a member can't decrypt — the person who HAS the key runs this.
228	  const redistributeRoomKey = useCallback(async (roomId: string, memberUserIds: string[]): Promise<boolean> => {
229	    if (!currentUserId) return false;
230	    const roomKey = await getRoomKey(roomId);
231	    if (!roomKey) return false; // caller doesn't have the key — can't redistribute
232	
233	    const privateKey = await getOrRestorePrivateKey();
234	    if (!privateKey) return false;
235	
236	    for (const memberId of memberUserIds) {
237	      const memberPublicKey = await getPublicKey(memberId);
238	      if (!memberPublicKey) continue;
239	      try {
240	        const encryptedKey = await wrapRoomKey(roomKey, privateKey, memberPublicKey);
241	        await supabase.from("room_encrypted_keys" as any).upsert(
242	          { room_id: roomId, user_id: memberId, encrypted_by: currentUserId, encrypted_key: encryptedKey },
243	          { onConflict: "room_id,user_id", ignoreDuplicates: true }
244	        );
245	      } catch (err) {
246	        console.error(`Failed to redistribute key for ${memberId}:`, err);
247	      }
248	    }
249	    return true;
250	  }, [currentUserId, getRoomKey, getOrRestorePrivateKey, getPublicKey]);
251	
252	  return {
253	    e2eReady,
254	    initEncryption,
255	    setupRoomEncryption,
256	    redistributeRoomKey,
257	    encrypt,
258	    decrypt,
259	    decryptMessages,
260	    getRoomKey,
261	    getPublicKey,
262	  };
263	}
