1	import { useState, useEffect, useCallback } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	
4	export interface AppNotification {
5	  id: string;
6	  type: string;
7	  title: string;
8	  body: string | null;
9	  data: Record<string, string> | null;
10	  read: boolean;
11	  created_at: string;
12	}
13	
14	const LIMIT = 40;
15	const clearedKey = (uid: string) => `crevia_notif_cleared_${uid}`;
16	
17	function getClearedAt(userId: string): string | null {
18	  return localStorage.getItem(clearedKey(userId));
19	}
20	
21	function applyFilter(data: AppNotification[], userId: string): AppNotification[] {
22	  const clearedAt = getClearedAt(userId);
23	  if (!clearedAt) return data;
24	  return data.filter((n) => n.created_at > clearedAt);
25	}
26	
27	export function useNotifications(userId: string) {
28	  const [notifications, setNotifications] = useState<AppNotification[]>([]);
29	  const [loading, setLoading] = useState(false);
30	
31	  const refresh = useCallback(async () => {
32	    if (!userId) return;
33	    setLoading(true);
34	    const { data } = await supabase
35	      .from("notifications")
36	      .select("id, type, title, body, data, read, created_at")
37	      .eq("user_id", userId)
38	      .order("created_at", { ascending: false })
39	      .limit(LIMIT);
40	    setNotifications(applyFilter((data as AppNotification[]) ?? [], userId));
41	    setLoading(false);
42	  }, [userId]);
43	
44	  useEffect(() => {
45	    if (!userId) return;
46	    refresh();
47	
48	    const handleCleared = () => setNotifications([]);
49	    window.addEventListener("crevia:notifications-cleared", handleCleared);
50	
51	    const channel = supabase
52	      .channel(`notifications:${userId}`)
53	      .on(
54	        "postgres_changes",
55	        { event: "INSERT", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
56	        (payload) => {
57	          const notif = payload.new as AppNotification;
58	          setNotifications((prev) => [notif, ...prev].slice(0, LIMIT));
59	        }
60	      )
61	      .on(
62	        "postgres_changes",
63	        { event: "UPDATE", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
64	        (payload) => {
65	          const updated = payload.new as AppNotification;
66	          setNotifications((prev) => {
67	            const without = prev.filter((n) => n.id !== updated.id);
68	            return [updated, ...without].slice(0, LIMIT);
69	          });
70	        }
71	      )
72	      .on(
73	        "postgres_changes",
74	        { event: "DELETE", schema: "public", table: "notifications", filter: `user_id=eq.${userId}` },
75	        (payload) => {
76	          const deleted = payload.old as { id: string };
77	          setNotifications((prev) => prev.filter((n) => n.id !== deleted.id));
78	        }
79	      )
80	      .subscribe();
81	
82	    return () => {
83	      supabase.removeChannel(channel);
84	      window.removeEventListener("crevia:notifications-cleared", handleCleared);
85	    };
86	  }, [userId, refresh]);
87	
88	  const markRead = useCallback(async (id: string) => {
89	    await supabase.from("notifications").update({ read: true }).eq("id", id);
90	    setNotifications((prev) =>
91	      prev.map((n) => (n.id === id ? { ...n, read: true } : n))
92	    );
93	  }, []);
94	
95	  const markAllRead = useCallback(async () => {
96	    if (!userId) return;
97	    await supabase
98	      .from("notifications")
99	      .update({ read: true })
100	      .eq("user_id", userId)
101	      .eq("read", false);
102	    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
103	  }, [userId]);
104	
105	  const clearAll = useCallback(async () => {
106	    if (!userId) return;
107	    // Store the cleared timestamp so notifications stay hidden across refreshes
108	    localStorage.setItem(clearedKey(userId), new Date().toISOString());
109	    await supabase.from("notifications").delete().eq("user_id", userId);
110	    window.dispatchEvent(new Event("crevia:notifications-cleared"));
111	  }, [userId]);
112	
113	  const unreadCount = notifications.filter((n) => !n.read).length;
114	
115	  return { notifications, unreadCount, loading, markRead, markAllRead, clearAll, refresh };
116	}
