140	// Proper URL detection without global regex issues
141	function linkifyContent(content: string): (string | JSX.Element)[] {
142	  const urlPattern = /(https?:\/\/[^\s<]+[^\s<.,;:!?"')\]])/g;
143	  const result: (string | JSX.Element)[] = [];
144	  let lastIndex = 0;
145	  let match: RegExpExecArray | null;
146	
147	  while ((match = urlPattern.exec(content)) !== null) {
148	    if (match.index > lastIndex) {
149	      result.push(content.slice(lastIndex, match.index));
150	    }
151	    const url = match[0];
152	    result.push(
153	      <a
154	        key={`link-${match.index}`}
155	        href={url}
156	        target="_blank"
157	        rel="noopener noreferrer"
158	        className="underline font-medium hover:opacity-80 break-all"
159	        onClick={(e) => e.stopPropagation()}
160	      >
161	        {url}
162	      </a>
163	    );
164	    lastIndex = match.index + url.length;
165	  }
166	
167	  if (lastIndex < content.length) {
168	    result.push(content.slice(lastIndex));
169	  }
170	
171	  return result.length > 0 ? result : [content];
172	}
