237	      // Verify every room member has a registered public key before encrypting.
238	      for (const memberId of memberIds) {
239	        const key = await getPublicKey(memberId);
240	        if (!key) {
241	          if (memberId === currentUserId) {
242	            // Own key is missing — re-run initialisation and block this send.
243	            initEncryption();
