245	          }
246	          const profile = members.find((m) => m.user_id === memberId)?.profile;
247	          const name = profile?.display_name || profile?.handle || "A participant";
248	          throw new Error(`${name} hasn't set up encryption yet. Message not sent.`);
249	        }
250	      }
251	
252	      // Attempt encryption using the current user's copy of the room key.
253	      let encrypted = await encrypt(plaintext, roomId);
254	
255	      if (!encrypted) {
256	        // Before generating a new key, check if any key already exists for this
257	        // room. If it does, we must not generate a new one — that would make all
258	        // previously encrypted messages unreadable. Instead, the other participant
259	        // needs to redistribute their copy of the existing key to us.
260	        const { data: existingKeys } = await (supabase
261	          .from("room_encrypted_keys" as any)
