268	          // party to open the chat, which triggers redistribution via selectRoom.
269	          throw new Error(
270	            "Securing chat... The other person needs to open the chat once to sync your key. Then try again."
271	          );
272	        }
273	
274	        // Truly new room — no key exists anywhere. Generate the first one.
275	        await setupRoomEncryption(roomId, memberIds);
276	        encrypted = await encrypt(plaintext, roomId);
277	      }
278	
279	      if (!encrypted) {
280	        throw new Error("Encryption failed. Please try again.");
281	      }
282	
283	      return { content: encrypted, is_encrypted: true };
284	    },
