859	      const { content: finalContent, is_encrypted } = await encryptContent(plainContent, selectedRoom.id);
860	
861	      // Privacy by Default — never allow a plaintext message to reach the DB.
862	      if (!is_encrypted) {
863	        throw new Error("Encryption is required. Message not sent.");
864	      }
865	
866	      const messageData: any = {
867	        room_id: selectedRoom.id,
868	        sender_id: currentUserId,
869	        content: finalContent,
