878	      // Add reply reference
879	      if (replyingTo) {
880	        messageData.reply_to_id = replyingTo.id;
881	      }
882	
883	      await supabase.from("chat_messages").insert(messageData);
884	
885	      // Patch the notification body the trigger just created with the real plaintext preview.
886	      supabase.rpc("update_message_notification_preview", {
887	        p_room_id: selectedRoom.id,
888	        p_preview: plainContent.slice(0, 120),
889	      });
890	
891	      await supabase
892	        .from("chat_rooms")
893	        .update({ updated_at: new Date().toISOString() })
894	        .eq("id", selectedRoom.id);
895	
896	      setNewMessage("");
897	      setSelectedFile(null);
898	      setReplyingTo(null);
899	      broadcastTyping(false);
900	    } catch (error) {
901	      console.error("Send error:", error);
902	      toast.error(error instanceof Error ? error.message : "Failed to send message");
903	    } finally {
904	      setUploadingFile(false);
905	    }
